import React, { useState } from 'react';
import InlineInput from '../UI/InlineInput';
import './ActionList.css';

const ActionList = ({ actions, itemId, userId }) => {
  const [creatingAction, setCreatingAction] = useState(false);
  const [newActionTitle, setNewActionTitle] = useState('');

  const handleCreateAction = async (title) => {
    if (!title.trim()) return;

    try {
      // This will be passed down from parent
      console.log('Creating action:', title, 'for item:', itemId);
      setNewActionTitle('');
      setCreatingAction(false);
    } catch (err) {
      console.error('Failed to create action:', err);
    }
  };

  const toggleActionStatus = async (actionId, currentStatus) => {
    try {
      // This will be passed down from parent
      const newStatus = currentStatus === 'completed' ? 'pending' : 'completed';
      console.log('Toggling action:', actionId, 'to:', newStatus);
    } catch (err) {
      console.error('Failed to update action:', err);
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'completed': return '#22c55e';
      case 'in_progress': return '#f59e0b';
      default: return '#6b7280';
    }
  };

  return (
    <div className="action-list">
      {actions.map((action) => (
        <div key={action.id} className="action">
          <div className="action-content">
            <button
              className={`action-checkbox ${action.status}`}
              onClick={() => toggleActionStatus(action.id, action.status)}
              style={{ borderColor: getStatusColor(action.status) }}
            >
              {action.status === 'completed' && '✓'}
            </button>

            <div className="action-info">
              <span className="action-title">{action.title}</span>
              {action.description && (
                <span className="action-description">{action.description}</span>
              )}
            </div>
          </div>
        </div>
      ))}

      {/* Add New Action */}
      {creatingAction ? (
        <div className="new-action">
          <InlineInput
            value={newActionTitle}
            onChange={setNewActionTitle}
            onSubmit={handleCreateAction}
            onCancel={() => {
              setCreatingAction(false);
              setNewActionTitle('');
            }}
            placeholder="Action title..."
            autoFocus
          />
        </div>
      ) : (
        <button
          onClick={() => setCreatingAction(true)}
          className="add-action-inline-button"
        >
          + Add action
        </button>
      )}
    </div>
  );
};

export default ActionList;

