import React, { useState, useEffect } from 'react';
import { useFocalBoard } from '../../hooks/useFocalBoard';
import LaneList from './LaneList';
import InlineInput from '../UI/InlineInput';
import './FocalBoard.css';

const FocalBoard = ({ userId, selectedFocalFromNav }) => {
  const {
    focals,
    selectedFocal,
    lanes,
    items,
    actions,
    loading,
    error,
    createFocal,
    createLane,
    selectFocal,
    clearError
  } = useFocalBoard(userId);

  const [isCreatingFocal, setIsCreatingFocal] = useState(false);
  const [newFocalName, setNewFocalName] = useState('');

  const handleCreateFocal = async (name) => {
    if (!name.trim()) return;

    try {
      const newFocal = await createFocal(name.trim());
      selectFocal(newFocal);
      setNewFocalName('');
      setIsCreatingFocal(false);
      console.log('✅ Focal created successfully:', newFocal);
    } catch (err) {
      console.error('❌ Failed to create focal:', err);
      // Show error to user
      alert(`Failed to create focal: ${err.message || 'Unknown error'}`);
      setIsCreatingFocal(false);
      setNewFocalName('');
    }
  };

  const handleCreateLane = async (name, itemLabel = null) => {
    if (!selectedFocal || !name.trim()) return;

    try {
      await createLane(selectedFocal.id, name.trim(), itemLabel);
    } catch (err) {
      console.error('Failed to create lane:', err);
    }
  };

  // Auto-select focal if coming from navigation
  useEffect(() => {
    console.log('🔍 FocalBoard: Checking auto-select focal');
    console.log('🔍 FocalBoard: selectedFocalFromNav:', selectedFocalFromNav);
    console.log('🔍 FocalBoard: available focals:', focals.map(f => ({ name: f.name, id: f.id })));

    if (selectedFocalFromNav && focals.length > 0) {
      const matchingFocal = focals.find(f => f.name === selectedFocalFromNav);
      console.log('🔍 FocalBoard: matchingFocal:', matchingFocal);

      if (matchingFocal) {
        console.log('🔍 FocalBoard: Selecting matching focal:', matchingFocal.name);
        selectFocal(matchingFocal);
      } else {
        console.log('🔍 FocalBoard: No matching focal found for:', selectedFocalFromNav);
        // Try to find by partial match or case-insensitive
        const partialMatch = focals.find(f => 
          f.name.toLowerCase().includes(selectedFocalFromNav.toLowerCase()) ||
          selectedFocalFromNav.toLowerCase().includes(f.name.toLowerCase())
        );
        console.log('🔍 FocalBoard: partialMatch:', partialMatch);

        if (partialMatch) {
          console.log('🔍 FocalBoard: Selecting partial match:', partialMatch.name);
          selectFocal(partialMatch);
        }
      }
    }
  }, [selectedFocalFromNav, focals, selectFocal]);

  if (loading && focals.length === 0) {
    return (
      <div className="focal-board loading">
        <div className="loading-message">Loading your focals...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="focal-board error">
        <div className="error-message">
          Error: {error}
          <button onClick={clearError} className="retry-button">Retry</button>
        </div>
      </div>
    );
  }

  return (
    <div className="focal-board">
      {/* Header */}
      <div className="focal-board-header">
        <h2>
          {selectedFocal ? selectedFocal.name : 'Select a Focal'}
        </h2>

        {/* Add Focal Button */}
        {!selectedFocal && (
          <div className="add-focal-section">
            {isCreatingFocal ? (
              <InlineInput
                value={newFocalName}
                onChange={setNewFocalName}
                onSubmit={handleCreateFocal}
                onCancel={() => {
                  setIsCreatingFocal(false);
                  setNewFocalName('');
                }}
                placeholder="Focal name..."
                autoFocus
              />
            ) : (
              <button
                onClick={() => setIsCreatingFocal(true)}
                className="add-focal-button"
              >
                + New Focal
              </button>
            )}
          </div>
        )}
      </div>

      {/* Main Content */}
      {selectedFocal ? (
        <LaneList
          lanes={lanes}
          items={items}
          actions={actions}
          onCreateLane={handleCreateLane}
          userId={userId}
        />
      ) : (
        <div className="no-focal-selected">
          <div className="no-focal-message">
            <h3>No Focal Selected</h3>
            <p>Choose a focal from the sidebar or create a new one to get started.</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default FocalBoard;

