import React, { useState } from 'react';
import ActionList from './ActionList';
import InlineInput from '../UI/InlineInput';
import './ItemList.css';

const ItemList = ({ items, actions, laneId, userId, getItemActions }) => {
  const [expandedItems, setExpandedItems] = useState(new Set());
  const [creatingItemId, setCreatingItemId] = useState(null);
  const [newItemTitle, setNewItemTitle] = useState('');

  const toggleItemExpansion = (itemId) => {
    setExpandedItems(prev => {
      const newSet = new Set(prev);
      if (newSet.has(itemId)) {
        newSet.delete(itemId);
      } else {
        newSet.add(itemId);
      }
      return newSet;
    });
  };

  const handleCreateItem = async (title) => {
    if (!title.trim()) return;

    try {
      // This will be passed down from parent
      console.log('Creating item:', title, 'in lane:', laneId);
      setNewItemTitle('');
      setCreatingItemId(null);
    } catch (err) {
      console.error('Failed to create item:', err);
    }
  };

  const getItemStatus = (item) => {
    const itemActions = getItemActions(item.id);
    if (itemActions.length === 0) return item.status;

    const completedActions = itemActions.filter(action => action.status === 'completed').length;
    const totalActions = itemActions.length;

    if (completedActions === 0) return item.status;
    if (completedActions === totalActions) return 'completed';
    return 'in_progress';
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'completed': return '#22c55e';
      case 'in_progress': return '#f59e0b';
      default: return '#6b7280';
    }
  };

  return (
    <div className="item-list">
      {items.map((item) => {
        const isExpanded = expandedItems.has(item.id);
        const itemActions = getItemActions(item.id);
        const itemStatus = getItemStatus(item);
        const statusColor = getStatusColor(itemStatus);

        return (
          <div key={item.id} className="item">
            {/* Item Header */}
            <div 
              className="item-header"
              onClick={() => toggleItemExpansion(item.id)}
            >
              <div className="item-info">
                <div 
                  className="item-status-dot"
                  style={{ backgroundColor: statusColor }}
                />
                <span className="item-title">{item.title}</span>
                {item.description && (
                  <span className="item-description">{item.description}</span>
                )}
              </div>

              <div className="item-actions">
                {itemActions.length > 0 && (
                  <span className="action-count">
                    {itemActions.filter(a => a.status === 'completed').length}/{itemActions.length}
                  </span>
                )}
                <button 
                  className="expand-button"
                  onClick={(e) => {
                    e.stopPropagation();
                    toggleItemExpansion(item.id);
                  }}
                >
                  {isExpanded ? '▼' : '▶'}
                </button>
              </div>
            </div>

            {/* Actions (expandable) */}
            {isExpanded && (
              <div className="item-content">
                <ActionList
                  actions={itemActions}
                  itemId={item.id}
                  userId={userId}
                />

                {/* Add Action Button */}
                <div className="add-action-section">
                  <button className="add-action-button">
                    + Add Action
                  </button>
                </div>
              </div>
            )}
          </div>
        );
      })}

      {/* Add New Item */}
      {creatingItemId === 'new' ? (
        <div className="new-item">
          <InlineInput
            value={newItemTitle}
            onChange={setNewItemTitle}
            onSubmit={handleCreateItem}
            onCancel={() => {
              setCreatingItemId(null);
              setNewItemTitle('');
            }}
            placeholder="Item title..."
            autoFocus
          />
        </div>
      ) : (
        <button
          onClick={() => setCreatingItemId('new')}
          className="add-item-button"
        >
          + Add Item
        </button>
      )}
    </div>
  );
};

export default ItemList;

