import React, { useState } from 'react';
import ItemList from './ItemList';
import InlineInput from '../UI/InlineInput';
import './LaneList.css';

const LaneList = ({ lanes, items, actions, onCreateLane, userId }) => {
  const [isCreatingLane, setIsCreatingLane] = useState(false);
  const [newLaneLabel, setNewLaneLabel] = useState('');

  const handleCreateLane = async (laneName) => {
    if (!laneName.trim()) return;

    try {
      // For now, use the lane name as the item label too
      // In the future, we might want to separate these
      await onCreateLane(laneName.trim(), laneName.trim());
      setNewLaneLabel('');
      setIsCreatingLane(false);
    } catch (err) {
      console.error('Failed to create lane:', err);
    }
  };

  const getItemsForLane = (laneId) => {
    return items.filter(item => item.lane_id === laneId);
  };

  const getActionsForItem = (itemId) => {
    return actions.filter(action => action.item_id === itemId);
  };

  return (
    <div className="lane-list">
      {lanes.map((lane, index) => (
        <div key={lane.id} className="lane">
          {/* Lane Header */}
          <div className="lane-header">
            <h3 className="lane-title">
              {lane.item_label || 'Items'}
            </h3>
            <div className="lane-actions">
              <button className="lane-action-button" title="Add Item">
                +
              </button>
            </div>
          </div>

          {/* Items in Lane */}
          <ItemList
            items={getItemsForLane(lane.id)}
            actions={actions}
            laneId={lane.id}
            userId={userId}
            getItemActions={getActionsForItem}
          />
        </div>
      ))}

      {/* Add New Lane */}
      <div className="add-lane-section">
        {isCreatingLane ? (
          <InlineInput
            value={newLaneLabel}
            onChange={setNewLaneLabel}
            onSubmit={handleCreateLane}
            onCancel={() => {
              setIsCreatingLane(false);
              setNewLaneLabel('');
            }}
            placeholder="Lane label (e.g., Tasks, Leads, Workouts)..."
            autoFocus
          />
        ) : (
          <button
            onClick={() => setIsCreatingLane(true)}
            className="add-lane-button"
          >
            + Add Lane
          </button>
        )}
      </div>
    </div>
  );
};

export default LaneList;

