import React, { useEffect, useRef } from 'react';
import './InlineInput.css';

const InlineInput = ({ 
  value, 
  onChange, 
  onSubmit, 
  onCancel, 
  placeholder = '', 
  autoFocus = false 
}) => {
  const inputRef = useRef(null);

  useEffect(() => {
    if (autoFocus && inputRef.current) {
      inputRef.current.focus();
      inputRef.current.select();
    }
  }, [autoFocus]);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (onSubmit && value.trim()) {
      onSubmit(value);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Escape') {
      e.preventDefault();
      if (onCancel) onCancel();
    }
  };

  return (
    <form onSubmit={handleSubmit} className="inline-input-form">
      <input
        ref={inputRef}
        type="text"
        value={value}
        onChange={(e) => onChange(e.target.value)}
        onKeyDown={handleKeyDown}
        placeholder={placeholder}
        className="inline-input"
        autoFocus={autoFocus}
      />
      <button type="submit" className="inline-input-submit">
        ✓
      </button>
      {onCancel && (
        <button 
          type="button" 
          onClick={onCancel} 
          className="inline-input-cancel"
        >
          ✕
        </button>
      )}
    </form>
  );
};

export default InlineInput;

