function buildAttachTags(selection: Record<string, AttachMode>): string[] {
  return Object.entries(selection).map(([id, mode]) => `attach:${id}:${mode}`);
}

function extractAttachSelection(tags: string[] | undefined): Record<string, AttachMode> {
  if (!tags?.length) {
    return {};
  }
  return tags.reduce<Record<string, AttachMode>>((acc, tag) => {
    if (!tag.startsWith('attach:')) {
      return acc;
    }
    const [, id, mode] = tag.split(':');
    if (!id || (mode !== 'node_only' && mode !== 'with_children')) {
      return acc;
    }
    acc[id] = mode;
    return acc;
  }, {});
}

interface AttachNodeRowProps {
  node: AttachNode;
  depth?: number;
  selected: Record<string, AttachMode>;
  onToggle: (id: string) => void;
  onModeChange: (id: string, mode: AttachMode) => void;
}

function AttachNodeRow({
  node,
  depth = 0,
  selected,
  onToggle,
  onModeChange
}: AttachNodeRowProps): JSX.Element {
  const activeMode = selected[node.id];
  return (
    <div className="attach-node-row" style={{ marginLeft: `${depth * 10}px` }}>
      <label className="attach-node-main">
        <input
          type="checkbox"
          checked={Boolean(activeMode)}
          onChange={() => onToggle(node.id)}
        />
        <span>{node.label}</span>
      </label>
      {activeMode && (
        <select
          className="calendar-input attach-node-mode"
          value={activeMode}
          onChange={(event) => onModeChange(node.id, event.target.value as AttachMode)}
        >
          <option value="node_only">Just this node</option>
          <option value="with_children">Node + all downstream</option>
        </select>
      )}
      {node.children?.map((child) => (
        <AttachNodeRow
          key={child.id}
          node={child}
          depth={depth + 1}
          selected={selected}
