import { authService } from '../services/authService';

interface HeaderProps {
  isAiOpen: boolean;
  onToggleAi: () => void;
  onCloseAi: () => void;
  aiContextTags: string[];
  onRemoveAiContextTag: (tag: string) => void;
}

