                  setShowSettingsMenu(!showSettingsMenu);
                } else {
                  navigate(item.path);
                }
              }}>
                <Icon />
                <span className="sidebar-nav-text">{item.name}</span>
              </button>
            );
          })}

          {/* Settings dropdown */}
          {showSettingsMenu && (
            <div className="settings-dropdown">
