        <div className="sidebar-divider-item" />

        <div className="sidebar-nav-items">
          <div className="focals-dropdown-container">
            <button
              className="sidebar-nav-item focals-toggle group"
              onClick={(e) => {
                e.stopPropagation();
                if (!isExpanded) {
                  // If collapsed, open sidebar and show focals
                  setIsExpanded(true);
                  setFocalsDropdownOpen(true);
                } else {
                  // If expanded, toggle dropdown
                  setFocalsDropdownOpen(!focalsDropdownOpen);
                }
              }}
            >
              <span className="relative flex items-center justify-center w-5 h-5">
                {/* Aperture icon (visible by default) */}
                <span className="focals-icon transition-opacity group-hover:opacity-0">
                  <ApertureIcon />
                </span>
                {/* Chevron icon (visible on hover) */}
                <span className={`absolute transition-opacity opacity-0 group-hover:opacity-100 transition-transform ${
                  focalsDropdownOpen ? 'rotate-180' : 'rotate-0'
                }`}>
                  <ChevronDown size={16} />
                </span>
              </span>
              <span className="sidebar-nav-text">Focals</span>
              {isExpanded && (
                <button
                  className="add-focal-btn"
                  onClick={(e) => {
                    e.stopPropagation();
                    setShowNewFocalInput(!showNewFocalInput);
                    if (showNewFocalInput) {
                      setNewFocalName('');
                      setCreateError('');
                    }
                  }}
                >
                  <Plus size={14} />
                </button>
              )}
            </button>

            {/* Focals dropdown - only shows when expanded and dropdown open */}
            {focalsDropdownOpen && isExpanded && (
              <div className="focals-dropdown show">
                {/* Only show focals list when there are focals */}
                {focals.length > 0 && (
                  focals.map((focal) => (
                    <button
                      key={focal.id}
                      className={`focal-item ${focal.name === selectedFocalFromNav ? 'selected' : ''}`}
                      onClick={() => handleFocalClick(focal)}
                    >
                      {focal.name}
                    </button>
                  ))
                )}
              </div>
            )}

            {/* New focal input - shows when + is clicked, regardless of dropdown state */}
            {showNewFocalInput && isExpanded && (
              <div className="new-focal-input show">
                <input
                  type="text"
                  value={newFocalName}
                  onChange={(e) => setNewFocalName(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' && !isCreating) {
                      console.log('🎯 Enter detected, calling handleAddFocal');
                      e.preventDefault();
                      handleAddFocal();
                    } else if (e.key === 'Escape') {
                      console.log('🚪 Escape detected');
                      setShowNewFocalInput(false);
                      setNewFocalName('');
                      setCreateError('');
                    }
                  }}
                  disabled={isCreating}
                  placeholder={isCreating ? 'Creating...' : 'Focal name...'}
                  autoFocus
                  className={isCreating ? 'creating' : ''}
                />
                {newFocalName && !isCreating && (
                  <CornerDownLeft className="enter-icon" />
                )}
                {createError && (
                  <div className="focal-create-error">
                    {createError}
                  </div>
                )}
              </div>
            )}
          </div>
        </div>

        <div className="sidebar-divider-item" />

        <div className="sidebar-nav-items">
          <button className="sidebar-nav-item" onClick={() => navigate('/docs')}>
            <FileText size={14} />
            <span className="sidebar-nav-text">Docs</span>
          </button>
        </div>

        {/* Footer with collapse and settings */}
        <div className="sidebar-footer">
          <button 
            className="sidebar-nav-item sidebar-expand-btn"
            onClick={() => setIsExpanded(!isExpanded)}
          >
            <ChevronLeft className={`sidebar-expand-icon ${isExpanded ? 'rotated' : ''}`} />
            <span className="sidebar-nav-text">Collapse</span>
          </button>

          <button 
            className="sidebar-nav-item settings-button"
            onClick={(e) => {
              e.stopPropagation();
              setShowSettingsMenu(!showSettingsMenu);
            }}
          >
            <Settings size={14} />
            <span className="sidebar-nav-text">Settings</span>
          </button>

          {showSettingsMenu && (
            <div className="settings-dropdown">
              <div className="settings-header">
                <div className="user-info">
                  <User size={14} />
                  <span>{user?.email}</span>
                </div>
              </div>
              <div className="settings-divider"></div>
              <button
                className="settings-option"
                onClick={() => {
                  setShowSettingsMenu(false);
                  navigate('/settings');
                }}
              >
                <Settings size={14} />
                <span>Preferences</span>
              </button>
              <button
                className="settings-option logout"
                onClick={handleLogout}
              >
                <LogOut size={14} />
                <span>Sign Out</span>
              </button>
            </div>
          )}
        </div>
      </div>
    </nav>
  );
}

