// Focal Board Service - uses shared Supabase client
export const focalBoardService = {
  // FOCALS
  async getFocals(userId) {
    const { data, error } = await supabase
      .from('focals')
      .select('*')
      .eq('user_id', userId)
      .order('order_num', { ascending: true });

    if (error) throw error;
    return data;
  },

  async createFocal(userId, name) {
    console.log('🔧 focalBoardService.createFocal called with:', { userId, name });

    try {
      // Get the highest order_num for this user
      console.log('🔧 Getting existing focals for order...');
      const { data: existingFocals } = await supabase
        .from('focals')
        .select('order_num')
        .eq('user_id', userId)
        .order('order_num', { ascending: false })
        .limit(1);

      console.log('🔧 Existing focals for order:', existingFocals);

      const nextOrder = existingFocals?.[0]?.order_num + 1 || 0;
      console.log('🔧 Next order:', nextOrder);

      const focalData = {
        name, 
        user_id: userId, 
        order_num: nextOrder
      };
      console.log('🔧 About to insert focal data:', focalData);

