  },

  async createAction(itemId, userId, title, description = null, scheduledAt = null) {
    // Get the highest order_num for this item
    const { data: existingActions } = await supabase
      .from('actions')
      .select('order_num')
      .eq('item_id', itemId)
      .order('order_num', { ascending: false })
      .limit(1);

