  async deleteAction(id) {
    const { error } = await supabase
      .from('actions')
      .delete()
      .eq('id', id);

    if (error) throw error;
  },

  // BATCH OPERATIONS
  async getFullFocalData(focalId) {
    const { data, error } = await supabase
      .from('lanes')
      .select(`
        *,
        items (
          *,
          actions (*)
        )
      `)
      .eq('focal_id', focalId)
      .order('position', { ascending: true });

    if (error) throw error;
    return data;
  }
};

